questions.explanation:
## Why This Is Asked

Tests the ability to design a comprehensive debugging methodology for cross-DC TLS failures in Consul Connect service mesh, emphasizing certificate lifecycle management, SPIFFE identity consistency, and Envoy proxy TLS inspection under production load.

## Key Concepts

- Cross-DC trust root propagation and automated certificate rotation
- SPIFFE identity generation, mapping, and intention-based access control
- Envoy TLS termination, SNI handling, and certificate chain validation
- Mesh gateway configuration and traffic management strategies
- Production-safe debugging with canary deployments and rollback procedures
- Network-level troubleshooting with packet capture and TLS analysis tools

## Code Example

```javascript
// TLS handshake analysis script for service mesh debugging
const tls = require('tls');
const fs = require('fs');

function analyzeTLSHandshake(host, port, callback) {
  const socket = tls.connect({
    host: host,
    port: port,
    servername: host,
    rejectUnauthorized: false // For analysis only
  }, () => {
    const cert = socket.getPeerCertificate();
    const info = {
      subject: cert.subject,
      sans: cert.subjectaltname,
      issuer: cert.issuer,
      validFrom: cert.valid_from,
      validTo: cert.valid_to,
      spiffeId: extractSPIFFEId(cert)
    };
    socket.destroy();
    callback(null, info);
  });

  socket.on('error', (err) => {
    callback(err, null);
  });
}

function extractSPIFFEId(cert) {
  const sanMatch = cert.subjectaltname?.match(/URI:spiffe:([^\s,]+)/);
  return sanMatch ? sanMatch[1] : null;
}

// Usage for cross-DC verification
['dc1-auth-proxy.service.consul', 'dc2-auth-proxy.service.consul'].forEach(host => {
  analyzeTLSHandshake(host, 443, (err, info) => {
    if (err) {
      console.error(`Failed to connect to ${host}:`, err.message);
    } else {
      console.log(`${host} TLS info:`, JSON.stringify(info, null, 2));
    }
  });
});
```

This systematic approach isolates certificate lifecycle issues, validates SPIFFE identity consistency, and provides rollback mechanisms for production environments.
